declare query_parameters (startTime:datetime, _placeHolder__end:datetime);
let InNeighborhood = dynamic(null);
let InStreet = dynamic(null);
let FilterBikeStream = () {
    Bikestream
    | where isempty(['InNeighborhood']) or Neighbourhood in (['InNeighborhood'])
    | where isempty(['InStreet']) or Street in (['InStreet'])
    | extend ingestionTime = ingestion_time()
    | extend fill_rate = toreal(No_Bikes) / (No_Bikes + No_Empty_Docks)
};
let minimumTime = toscalar(FilterBikeStream | summarize min(ingestionTime));
let from=max_of(startTime, minimumTime);
FilterBikeStream
| make-series emptyDocks=max(No_Empty_Docks)  default=int(null)
    on ingestionTime from from to now() step max_of((now() - from)/100, 1d) by BikepointID
| extend emptyDocks = series_fill_linear(emptyDocks)
| mvexpand emptyDocks, ingestionTime
| summarize ['Available Docks'] = sum(toint(emptyDocks)) by todatetime(ingestionTime)
